import torch
import torch.nn as nn
import triton
import triton.language as tl

# Test if tl.static_range works with different kernel sizes
@triton.jit
def test_kernel(
    KERNEL_H: tl.constexpr,
    KERNEL_W: tl.constexpr,
):
    acc = 0.0
    for kh in tl.static_range(KERNEL_H):
        for kw in tl.static_range(KERNEL_W):
            acc += kh * kw
    return acc

# Try compiling with different sizes
print('Testing static_range with KERNEL_H=3, KERNEL_W=7')
try:
    test_kernel[(1,)](KERNEL_H=3, KERNEL_W=7)
    print('Success!')
except Exception as e:
    print('Error:', e)
